                issues.append(f'APPT-20260520-001 Actual_Departure_Time should be blank but is "{departure_val}"')

    # Check APPT-20260520-002
    if appt_002 is None:
        issues.append('APPT-20260520-002 not found in dock_schedule.xlsx')
