from pathlib import Path
import openpyxl
import datetime

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('receiving_log.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*receiving*log*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'receiving_log.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    # Find headers
    header_row = None
    headers = {}
    for row in ws.iter_rows():
        for cell in row:
            if cell.value and 'receipt' in str(cell.value).lower():
                header_row = cell.row
                break
        if header_row:
            for cell in ws[header_row]:
                if cell.value:
                    key = str(cell.value).strip().lower().replace(' ', '_')
                    headers[key] = cell.column
            break

    if not header_row:
        return {'pass': False, 'score': 0.0, 'feedback': 'Could not find header row in receiving_log.xlsx'}

    # Exact match first, then substring fallback
    def find_col(*keywords):
        for kw in keywords:
            kw_lower = kw.lower()
            if kw_lower in headers:
                return headers[kw_lower]
        for kw in keywords:
            kw_lower = kw.lower()
            for k, v in headers.items():
                if kw_lower in k:
                    return v
        return None

    receipt_col     = find_col('receipt_id')
    arrival_col     = find_col('arrival_timestamp', 'arrival_time', 'arrival')
    dock_col        = find_col('dock_door', 'dock')
    supplier_col    = find_col('supplier_id')
    carrier_col     = find_col('carrier_name', 'carrier')
    coord_col       = find_col('coordinator_initials', 'coordinator', 'initials')
    po_num_col      = find_col('po_number', 'po_num')
    po_line_col     = find_col('po_line')
    sku_col         = find_col('sku')
    safety_col      = find_col('safety_critical', 'safety')
    qty_ordered_col = find_col('qty_ordered', 'quantity_ordered')
    qty_slip_col    = find_col('qty_claimed_on_slip', 'qty_claimed', 'claimed_on_slip')
    status_col      = find_col('status')

    target_row = None
    for row in ws.iter_rows(min_row=header_row + 1):
        if receipt_col and receipt_col <= len(row):
            val = str(row[receipt_col - 1].value or '').strip()
            if val == 'REC-20260520-001':
                target_row = row
                break

    if target_row is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'Row REC-20260520-001 not found in receiving_log.xlsx'}

    def get_val(col):
        if col and col <= len(target_row):
            return target_row[col - 1].value
        return None

    issues = []

    # Arrival timestamp: 05/20/2026 07:02
    arrival_val = get_val(arrival_col)
    if arrival_val is None:
        issues.append('Arrival_Timestamp is blank')
    else:
        arrival_str = str(arrival_val).strip()
        if isinstance(arrival_val, datetime.datetime):
            if not (arrival_val.month == 5 and arrival_val.day == 20 and arrival_val.year == 2026
                    and arrival_val.hour == 7 and arrival_val.minute == 2):
                issues.append(f'Arrival_Timestamp is {arrival_val}, expected 05/20/2026 07:02')
        else:
            if '05/20/2026' not in arrival_str and '2026-05-20' not in arrival_str:
                issues.append(f'Arrival_Timestamp does not contain 05/20/2026: got "{arrival_str}"')
            if '7:02' not in arrival_str and '07:02' not in arrival_str:
                issues.append(f'Arrival_Timestamp does not contain 07:02: got "{arrival_str}"')

    # Dock Door
    dock_val = str(get_val(dock_col) or '').strip()
    if 'dock 2' not in dock_val.lower() and 'dock2' not in dock_val.lower().replace(' ', ''):
        issues.append(f'Dock_Door is "{dock_val}", expected Dock 2')

    # Supplier ID
    sup_val = str(get_val(supplier_col) or '').strip()
    if sup_val != 'SUP-0155':
        issues.append(f'Supplier_ID is "{sup_val}", expected SUP-0155')

    # Carrier Name
    carrier_val = str(get_val(carrier_col) or '').strip()
    if 'xpo' not in carrier_val.lower():
        issues.append(f'Carrier_Name is "{carrier_val}", expected XPO Logistics')

    # Coordinator Initials - just check it's populated
    coord_val = get_val(coord_col)
    if coord_val is None or str(coord_val).strip() == '':
        issues.append('Coordinator_Initials is blank, expected to be populated')

    # PO Number
    po_val = str(get_val(po_num_col) or '').strip()
    if po_val != 'MER-PO-104903':
        issues.append(f'PO_Number is "{po_val}", expected MER-PO-104903')

    # PO Line
    po_line_val = str(get_val(po_line_col) or '').strip()
    if po_line_val not in ('2', '002', '2.0'):
        issues.append(f'PO_Line is "{po_line_val}", expected 002')

    # SKU
    sku_val = str(get_val(sku_col) or '').strip()
    if sku_val != 'FS-10091-B1':
        issues.append(f'SKU is "{sku_val}", expected FS-10091-B1')

    # Safety Critical
    safety_val = str(get_val(safety_col) or '').strip().upper()
    if safety_val not in ('Y', 'YES', 'TRUE', '1'):
        issues.append(f'Safety_Critical is "{safety_val}", expected Y')

    # Qty Ordered
    qty_ord_val = get_val(qty_ordered_col)
    try:
        if abs(float(str(qty_ord_val or '0').replace(',', '')) - 1800) > 1:
            issues.append(f'Qty_Ordered is {qty_ord_val}, expected 1800')
    except (ValueError, TypeError):
        issues.append(f'Qty_Ordered is "{qty_ord_val}", expected 1800')

    # Qty Claimed On Slip
    qty_slip_val = get_val(qty_slip_col)
    try:
        if abs(float(str(qty_slip_val or '0').replace(',', '')) - 1600) > 1:
            issues.append(f'Qty_Claimed_On_Slip is {qty_slip_val}, expected 1600')
    except (ValueError, TypeError):
        issues.append(f'Qty_Claimed_On_Slip is "{qty_slip_val}", expected 1600')

    # Status
    status_val = str(get_val(status_col) or '').strip().lower()
    if 'awaiting' not in status_val and 'count' not in status_val:
        issues.append(f'Status is "{status_val}", expected "Awaiting Count"')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': 'REC-20260520-001 issues: ' + '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': 'REC-20260520-001 row found with all required fields correctly populated.'}

from pathlib import Path
import re
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Find the receiving log file - be generous with naming
    xlsx_files = list(Path(workspace_path).glob('receiving_log.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*receiving*log*.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('**/receiving_log.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('**/*receiving*log*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'receiving_log.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    # Find header row
    header_row = None
    headers = {}
    for row in ws.iter_rows():
        for cell in row:
            if cell.value and any(kw in str(cell.value).lower() for kw in ['receipt', 'notes', 'id', 'record']):
                header_row = cell.row
                break
        if header_row:
            for cell in ws[header_row]:
                if cell.value:
                    key = str(cell.value).strip().lower().replace(' ', '_')
                    headers[key] = cell.column
            break

    if not header_row:
        return {'pass': False, 'score': 0.0, 'feedback': 'Could not find header row in receiving_log.xlsx'}

    # Helper to find columns loosely
    def find_col(*keywords):
        for kw in keywords:
            if kw.lower() in headers:
                return headers[kw.lower()]
        for kw in keywords:
            for k, v in headers.items():
                if kw.lower() in k:
                    return v
        return None

    receipt_col = find_col('receipt_id', 'receipt', 'rec_id', 'id')
    notes_col = find_col('notes', 'note', 'comments', 'comment', 'remarks')

    if not receipt_col:
        return {'pass': False, 'score': 0.0, 'feedback': f'Receipt_ID column not found in receiving_log.xlsx. Headers found: {headers}'}

    # Find the target row
    target_row = None
    for row in ws.iter_rows(min_row=header_row + 1):
        if receipt_col <= len(row):
            val = str(row[receipt_col - 1].value or '').strip()
            if val == 'REC-20260520-001':
                target_row = row
                break

    if target_row is None:
        # Also try searching all cells for the receipt ID
        all_receipt_ids = []
        for row in ws.iter_rows(min_row=header_row + 1):
            if receipt_col <= len(row):
                all_receipt_ids.append(str(row[receipt_col - 1].value or '').strip())
        return {'pass': False, 'score': 0.0, 'feedback': f'REC-20260520-001 not found in receiving_log.xlsx. Receipt IDs found: {all_receipt_ids[:20]}'}

    # Extract notes text
    notes_text = ''
    if notes_col and notes_col <= len(target_row):
        notes_text = str(target_row[notes_col - 1].value or '')
    else:
        # Fallback: join all cell values in the row
        notes_text = ' '.join(str(c.value or '') for c in target_row)

    notes_lower = notes_text.lower()
    issues = []

    # The rubric requires: "Partial PO fulfillment: this shipment covers PO line(s) 002"
    # We check for the key components loosely:

    # 1. Must mention partial fulfillment
    if not re.search(r'partial', notes_lower):
        issues.append('Notes does not mention "partial" fulfillment')

    # 2. Must reference PO line(s) 002 / line 002 / line 2
    if not (re.search(r'line\(?s?\)?\s*0*2\b', notes_lower) or re.search(r'\bline\s*0*2\b', notes_lower) or re.search(r'\b0*2\b', notes_lower)):
        issues.append('Notes does not mention PO line 002')

    # 3. Must indicate this shipment covers those lines
    if not re.search(r'cover|shipment', notes_lower):
        issues.append('Notes does not indicate shipment coverage')

    # 4. Must mention PO fulfillment context
    if not re.search(r'po|fulfil', notes_lower):
        issues.append('Notes does not reference PO fulfillment')

    if issues:
        return {
            'pass': False,
            'score': 0.0,
            'feedback': f'REC-20260520-001 Notes partial fulfillment issues: {"; ".join(issues)}. Notes found: "{notes_text[:300]}"'
        }

    return {
        'pass': True,
        'score': 1.0,
        'feedback': f'REC-20260520-001 Notes contains the required partial PO fulfillment notation for PO line(s) 002. Notes: "{notes_text[:200]}"'
    }

