    SUBSTR_COLS = ('qty_received', 'variance_unit', 'variance_pct', 'variance_percent')

    disp_cols = {}
    for k, v in headers.items():
        if k in EXACT_COLS or any(kw in k for kw in SUBSTR_COLS):
            disp_cols[k] = v

    # Verify all four required columns were found
    REQUIRED = ('qty_received', 'variance_unit', 'variance_pct', 'disposition')
    missing = []
    for kw in REQUIRED:
        if kw == 'disposition':
            if kw not in disp_cols:
                missing.append(kw)
        else:
            if not any(kw in k for k in disp_cols):
                missing.append(kw)
    if missing:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not find expected disposition columns in headers: {missing}. Found headers: {list(headers.keys())}'}

    target_row = None
    for row in ws.iter_rows(min_row=header_row + 1):
        if receipt_col <= len(row):
            val = str(row[receipt_col - 1].value or '').strip()
            if val == 'REC-20260520-001':
                target_row = row
                break

    if target_row is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'REC-20260520-001 not found in receiving_log.xlsx'}

    issues = []
    for col_name, col_idx in disp_cols.items():
        if col_idx <= len(target_row):
            val = target_row[col_idx - 1].value
            if val is not None and str(val).strip() not in ('', 'None', 'none'):
                issues.append(f'{col_name} is "{val}", expected blank')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': 'Disposition columns should be blank for REC-20260520-001: ' + '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': f'Disposition columns (Qty_Received, Variance_Units, Variance_Pct, Disposition) are all blank for REC-20260520-001. Checked columns: {list(disp_cols.keys())}'}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('receiving_log.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*receiving*log*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'receiving_log.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    # Find headers to identify receipt_id and arrival columns
    header_row = None
    headers = {}
    for row in ws.iter_rows():
        for cell in row:
            if cell.value and 'receipt' in str(cell.value).lower():
                header_row = cell.row
                break
        if header_row:
            for cell in ws[header_row]:
                if cell.value:
                    key = str(cell.value).strip().lower().replace(' ', '_')
                    headers[key] = cell.column
            break

    def find_col(*keywords):
        for kw in keywords:
            if kw.lower() in headers:
                return headers[kw.lower()]
        for kw in keywords:
            for k, v in headers.items():
                if kw.lower() in k:
                    return v
        return None

    receipt_col  = find_col('receipt_id', 'receipt')
    arrival_col  = find_col('arrival_timestamp', 'arrival_time', 'arrival')
    supplier_col = find_col('supplier_id')

    violations = []

    for row in ws.iter_rows(min_row=(header_row + 1) if header_row else 2):
        row_vals = {col: str(cell.value or '').strip() for col, cell in enumerate(row, start=1)}
        full_text = ' '.join(row_vals.values())

        receipt_val  = row_vals.get(receipt_col, '')  if receipt_col  else ''
        arrival_val  = row_vals.get(arrival_col, '')  if arrival_col  else ''
        supplier_val = row_vals.get(supplier_col, '') if supplier_col else ''

        # REC-20260520-002 should never exist regardless of date
        if receipt_val == 'REC-20260520-002':
            violations.append(f'Row {row[0].row}: Receipt_ID REC-20260520-002 found — Meridian truck has not arrived')

        # SUP-0374 or Meridian Packaging only flagged if the row is dated 05/20/2026 or later
        is_may20_or_later = '05/20/2026' in arrival_val or '2026-05-20' in arrival_val \
                            or any(f'05/{d}/2026' in arrival_val for d in range(20, 32)) \
                            or any(f'2026-05-{d:02d}' in arrival_val for d in range(20, 32))

        if is_may20_or_later:
            if supplier_val == 'SUP-0374':
                violations.append(f'Row {row[0].row}: SUP-0374 (Meridian) found with arrival date {arrival_val} — truck has not arrived')
            if 'meridian packaging' in full_text.lower():
                violations.append(f'Row {row[0].row}: "Meridian Packaging" reference found with arrival date {arrival_val}')

    if violations:
        return {'pass': False, 'score': 0.0, 'feedback': 'receiving_log.xlsx contains entries that should not exist: ' + '; '.join(violations)}

    return {'pass': True, 'score': 1.0, 'feedback': 'No invalid Meridian Packaging Supply entries found in receiving_log.xlsx (REC-20260520-002 absent; no SUP-0374 or Meridian Packaging rows dated 05/20/2026 or later). Correct.'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    slack_path = None
    for base in [external_services_path, workspace_path]:
        if base is None:
            continue
        p = Path(base) / 'slack_data.json'
        if p.exists():
            slack_path = p
            break

    if slack_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found'}

    with open(slack_path, 'r') as f:
        data = json.load(f)

    messages = data.get('messages', {})

    if 'C001' not in messages:
        return {'pass': False, 'score': 0.0, 'feedback': 'Channel C001 (#receiving-dock) not found in slack_data.json messages'}

    c001_messages = messages.get('C001', [])

    violations = []
    for msg in c001_messages:
        text = str(msg.get('text', '')).strip()
        text_lower = text.lower()
        if 'appt-20260520-002' in text_lower and ('arrival' in text_lower or 'arrived' in text_lower or 'cleared' in text_lower):
            violations.append(f'Found message about APPT-20260520-002 arrival: "{text[:200]}"')
        if 'meridian' in text_lower and ('arrival' in text_lower or 'arrived' in text_lower or 'cleared' in text_lower):
            violations.append(f'Found message about Meridian arrival: "{text[:200]}"')

    if violations:
        return {'pass': False, 'score': 0.0, 'feedback': 'Found arrival messages for APPT-20260520-002/Meridian that should not exist: ' + '; '.join(violations)}

    return {'pass': True, 'score': 1.0, 'feedback': 'No arrival message found for APPT-20260520-002 or Meridian Packaging Supply in #receiving-dock. Correct.'}

