        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found'}

    with open(slack_path, 'r') as f:
        data = json.load(f)

    channels = data.get('channels', {})
    messages = data.get('messages', {})

    # channels may be a dict {id: {...}} or a list [{id: ..., ...}]
    if isinstance(channels, list):
        dm_channel_ids = {
            ch['id'] for ch in channels
            if isinstance(ch, dict) and (ch.get('is_im', False) or ch.get('is_mpim', False))
        }
    else:
        dm_channel_ids = {
            cid for cid, ch in channels.items()
            if isinstance(ch, dict) and (ch.get('is_im', False) or ch.get('is_mpim', False))
        }

    violations = []

    for cid in dm_channel_ids:
        for msg in messages.get(cid, []):
            text = str(msg.get('text', ''))
            text_lower = text.lower()
            if 'mer-po-105004' in text_lower:
                violations.append(f'DM channel {cid} contains MER-PO-105004: "{text[:200]}"')
            elif 'meridian' in text_lower and ('unknown' in text_lower or 'po' in text_lower):
                violations.append(f'DM channel {cid} contains Meridian/PO reference: "{text[:200]}"')

    if violations:
        return {'pass': False, 'score': 0.0, 'feedback': 'DM channels contain Meridian/MER-PO-105004 messages that should not exist: ' + '; '.join(violations)}

    return {'pass': True, 'score': 1.0, 'feedback': f'No DM channel messages found referencing Meridian Packaging Supply or MER-PO-105004. DM channels checked: {dm_channel_ids or "none (no DM channels exist)"}. Correct.'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    slack_path = None
    for base in [external_services_path, workspace_path]:
        if base is None:
            continue
        p = Path(base) / 'slack_data.json'
        if p.exists():
            slack_path = p
            break

    if slack_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found'}

    with open(slack_path, 'r') as f:
        data = json.load(f)

    messages = data.get('messages', {})

    if 'C001' not in messages:
        return {'pass': False, 'score': 0.0, 'feedback': 'Channel C001 (#receiving-dock) not found in slack_data.json messages'}

    c001_messages = messages.get('C001', [])

    required_components = [
        'arrival on time',
        'appt-20260520-001',
        'ritter fastener',
        'dock 2',
        'mer-po-104903',
        'cleared to unload'
    ]

    found_msg = None
    wrong_user_msg = None

    for msg in c001_messages:
        user = str(msg.get('user', '')).strip()
        text = str(msg.get('text', '')).strip()
        text_lower = text.lower()

        components_ok = all(comp in text_lower for comp in required_components)
        user_ok = user in ('U001', 'U_MOCK_BOT') or 'mock_bot' in user.lower()

        if components_ok and user_ok:
            found_msg = text
            break
        elif components_ok and not user_ok:
            wrong_user_msg = (text, user)

    if found_msg:
        return {'pass': True, 'score': 1.0, 'feedback': f'Found arrival confirmation message in #receiving-dock: "{found_msg[:300]}"'}

    if wrong_user_msg:
        return {'pass': False, 'score': 0.0, 'feedback': f'Arrival confirmation message found but posted by wrong user "{wrong_user_msg[1]}" (expected U001 or U_MOCK_BOT): "{wrong_user_msg[0][:200]}"'}

    sample = [msg.get('text', '')[:100] for msg in c001_messages[-5:]] if c001_messages else []
    return {'pass': False, 'score': 0.0, 'feedback': f'No arrival confirmation message for APPT-20260520-001 found in #receiving-dock (C001). Required components: {required_components}. Last messages: {sample}'}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('open_pos.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*open*po*.xlsx')) + list(Path(workspace_path).glob('*po*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'open_pos.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active

    # Find headers
    header_row = None
    headers = {}
    for row in ws.iter_rows():
        for cell in row:
            if cell.value and 'po_number' in str(cell.value).lower().replace(' ', '_'):
                header_row = cell.row
                break
        if header_row:
            for cell in ws[header_row]:
                if cell.value:
                    key = str(cell.value).strip().lower().replace(' ', '_')
                    headers[key] = cell.column
            break

    if not header_row:
        return {'pass': False, 'score': 0.0, 'feedback': 'Could not find header row in open_pos.xlsx'}

    # Exact match first, then substring fallback
    def find_col(*keywords):
        for kw in keywords:
            if kw.lower() in headers:
                return headers[kw.lower()]
        for kw in keywords:
            for k, v in headers.items():
                if kw.lower() in k:
                    return v
        return None

    po_col   = find_col('po_number')
    line_col = find_col('po_line')

    # Find the target row
    target_row = None
    for row in ws.iter_rows(min_row=header_row + 1):
        po_val   = str(row[po_col - 1].value or '').strip() if po_col else ''
        line_val = str(row[line_col - 1].value or '').strip() if line_col else ''
        if po_val == 'MER-PO-104903' and line_val in ('2', '002', '2.0'):
            target_row = row
            break

    if target_row is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'Row MER-PO-104903 Line 002 not found in open_pos.xlsx'}

    def get_val(col):
        if col and col <= len(target_row):
            return target_row[col - 1].value
        return None

    def is_blank(val):
        return val is None or str(val).strip() in ('', 'None', 'none')

    issues = []

    # Expected values for all rubric-specified fields
    checks = [
        ('supplier_id',               'SUP-0155',                   lambda v: str(v or '').strip() == 'SUP-0155'),
        ('supplier_name',             'Ritter Fastener Group',       lambda v: 'ritter' in str(v or '').lower() and 'fastener' in str(v or '').lower()),
        ('sku',                       'FS-10091-B1',                 lambda v: str(v or '').strip() == 'FS-10091-B1'),
        ('qty_ordered',               '1800',                        lambda v: abs(float(str(v or '0').replace(',', '')) - 1800) <= 1),
        ('unit_price',                '3.20',                        lambda v: abs(float(str(v or '0').replace(',', '').replace('$', '')) - 3.20) <= 0.01),
        ('po_date',                   '03/20/2026',                  lambda v: '03/20/2026' in str(v or '') or '2026-03-20' in str(v or '')),
        ('requested_ship_date',       '04/28/2026',                  lambda v: '04/28/2026' in str(v or '') or '2026-04-28' in str(v or '')),
        ('required_delivery_date',    '05/12/2026',                  lambda v: '05/12/2026' in str(v or '') or '2026-05-12' in str(v or '')),
        ('safety_critical',           'Y',                           lambda v: str(v or '').strip().upper() in ('Y', 'YES', 'TRUE', '1')),
        ('hazmat_flag',               'N',                           lambda v: str(v or '').strip().upper() in ('N', 'NO', 'FALSE', '0')),
        ('dtl_flag',                  'N',                           lambda v: str(v or '').strip().upper() in ('N', 'NO', 'FALSE', '0')),
        ('approved_revisions',        'FS-10091-B1',                 lambda v: str(v or '').strip() == 'FS-10091-B1'),
        ('customer_doc_required',     'N',                           lambda v: str(v or '').strip().upper() in ('N', 'NO', 'FALSE', '0')),
        ('receipt_status',            'Open',                        lambda v: str(v or '').strip().lower() == 'open'),
    ]

    blank_checks = [
        'approved_substitutes', 'customer_substitutions', 'customer_override',
        'new_supplier_sc_approval', 'notes'
    ]

    for col_name, expected, check_fn in checks:
        col = find_col(col_name)
        if col is None:
            issues.append(f'Column "{col_name}" not found in headers')
            continue
        val = get_val(col)
        try:
            if not check_fn(val):
                issues.append(f'{col_name} is "{val}", expected {expected}')
        except (ValueError, TypeError):
            issues.append(f'{col_name} is "{val}", expected {expected}')

    for col_name in blank_checks:
        col = find_col(col_name)
        if col is None:
            continue  # column may not exist — skip rather than fail
        val = get_val(col)
        if not is_blank(val):
            issues.append(f'{col_name} is "{val}", expected blank')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': 'MER-PO-104903 Line 002 in open_pos.xlsx has unexpected changes: ' + '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': 'MER-PO-104903 Line 002 in open_pos.xlsx is unmodified with all original values correct.'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # Check mailbox.json in both workspace and external_services paths
    mailbox_path = None

    # First try external_services_path
    if external_services_path:
        candidate = Path(external_services_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    # Also check workspace_path
    if mailbox_path is None:
        candidate = Path(workspace_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    if mailbox_path is None:
        # If no mailbox.json found anywhere, that means no emails were sent.
        # Be generous: pass.
        return {"pass": True, "score": 1.0, "feedback": "No mailbox.json found in workspace or external services path. No sent emails exist, so the condition is satisfied."}

    try:
        with open(mailbox_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read mailbox.json at {mailbox_path}: {e}"}

    emails = data.get("emails", [])

    sent_emails = []
    for email in emails:
        folder = email.get("folder", "")
        if folder.lower() == "sent":
            sent_emails.append(email)

    if len(sent_emails) == 0:
        return {"pass": True, "score": 1.0, "feedback": f"No sent emails found in mailbox.json ({mailbox_path}). Total emails in mailbox: {len(emails)}."}
    else:
        subjects = [e.get("subject", "(no subject)") for e in sent_emails]
        return {"pass": False, "score": 0.0, "feedback": f"Found {len(sent_emails)} sent email(s) in mailbox.json, but expected none. Sent email subjects: {subjects}"}
